import{kn as e}from"./chunk-IjxM6APl.js";var t=e(),n={publishing_date:`2025-01-18`,title:`Are decentral websites a thing for me ?`,category:`webdev`,secondaryCategory:`blockchain`,description:`I explore decentralized web hosting using ENS domains and IPFS storage. Discover how blockchain enables censorship-resistant websites without traditional hosting companies.`};function r(e){let n={a:`a`,code:`code`,h2:`h2`,li:`li`,ol:`ol`,p:`p`,section:`section`,sup:`sup`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsxs)(n.p,{children:[`Over the last few years, I kept wondering what it might mean to host a "decentral" website very much like it is possible to decentralize certain financial services through smart contracts `,(0,t.jsx)(n.sup,{children:(0,t.jsx)(n.a,{href:`#user-content-fn-2`,id:`user-content-fnref-2`,"data-footnote-ref":!0,"aria-describedby":`footnote-label`,children:`1`})}),`. What would be needed ?`]}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`A decentral domain provider.`}),`
`,(0,t.jsx)(n.li,{children:`A simple way to update the website.`}),`
`,(0,t.jsx)(n.li,{children:`A decentralized storage system.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`As we will see the first and last part are fairly straight-forward. For the decentral storage I continue to have some doubts.`}),`
`,(0,t.jsx)(n.h2,{children:`Get an ENS domain`}),`
`,(0,t.jsxs)(n.p,{children:[`Normally, each website is hosted on some servers and you can access them through some domain. Currently, this website is hosted by github, which also delivers me directly the domain address. And behind Github is simply a big company which handles the domain registration for me. If I want to go decentral, I try to avoid this company and simply register the domain on a blockchain. This is already possible with `,(0,t.jsx)(n.a,{href:`https://ens.domains/`,children:`ENS`}),`. This is a great start as it gets us closer to have some fancy adress like `,(0,t.jsx)(n.code,{children:`fretchen.eth`}),`. To get this I needed to set up a wallet, where `,(0,t.jsx)(n.a,{href:`https://metamask.io/`,children:`Metamask`}),` seems to be the absolute standard nowadays. Once I have the wallet, I need to convert normal currency into the currency of the Blockchain, which is here `,(0,t.jsx)(n.a,{href:`https://ethereum.org/en/`,children:`ethereum`}),` `,(0,t.jsx)(n.sup,{children:(0,t.jsx)(n.a,{href:`#user-content-fn-1`,id:`user-content-fnref-1`,"data-footnote-ref":!0,"aria-describedby":`footnote-label`,children:`2`})}),`.`]}),`
`,(0,t.jsxs)(n.p,{children:[`To buy the ethereum, I had to go through `,(0,t.jsx)(n.a,{href:`https://www.kraken.com`,children:`Kraken`}),` and then send myself the ETH into the Metamask wallet. With the ETH I could quite simply register the domain of my choice with `,(0,t.jsx)(n.a,{href:`https://ens.domains/`,children:`ENS`}),`. The purchase itself is fairly straight-forward and interestingly the domain is implemented as an NFT. This is the tech that is mostly used to allow people to claim ownership for weird pictures of bored apes. Here, it basically gets you exclusive access rights to the domain, which actually sounds quite smart. The other cool thing is that `,(0,t.jsx)(n.code,{children:`ens.domains`}),` is a DAO. So there is no single authority controlling it, but a community of people. Another fairly cool feature.`]}),`
`,(0,t.jsx)(n.h2,{children:`A simple way to update the website`}),`
`,(0,t.jsxs)(n.p,{children:[`This is the part where it started to get slightly non-trivial. In the centralized world we have simple no-code systems like `,(0,t.jsx)(n.a,{href:`https://wordpress.org/`,children:`wordpress`}),` that run on a server. All of this is not really available on decentral systes. So we need some way to fall back into static website generation very much like I do here. But once, you can host a static website on `,(0,t.jsx)(n.a,{href:`https://pages.github.com/`,children:`github pages`}),`, it should also be theoretically ready to host it decentrally. Given that this is clearly solved (otherwise you would not read this), it was time to try to get this onto the block-chain.`]}),`
`,(0,t.jsx)(n.h2,{children:`A decentralized storage system`}),`
`,(0,t.jsxs)(n.p,{children:[`And this is now the part which was really quite annoying. At first, you think "Let me put it onto the blockchain". Well you quite quickly realize that this is totally cost-prohibitive and that you need some kind of alternative. The most famous and commonly used solution there is the `,(0,t.jsx)(n.a,{href:`https://ipfs.tech/`,children:`IPFS`}),`. As you put a file / folder into the IPFS it gets a CID and becomes discoverable for others. But in contrast to systems like ethereum it feels quite different:`]}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Either you have to run your own IPFS node, which is quite a bit of work. I never was able to have relible notes with acceptable download speeds.`}),`
`,(0,t.jsxs)(n.li,{children:[`Or you use a service like `,(0,t.jsx)(n.a,{href:`https://pinata.cloud/`,children:`Pinata`}),`, which is a centralized service that pins your files for you. This is quite a bit of a bummer, as it is not really decentralized anymore. Further you mostly have to pay through dollars etc. So there is really no clear difference to the world of standard cloud storages there.`]}),`
`]}),`
`,(0,t.jsx)(n.h2,{children:`Conclusion`}),`
`,(0,t.jsx)(n.p,{children:`And this is also the moment at which I wrote this blog post. I could now try to pay for the pinning service, put the CID onto eth.domains and claim some decentralized website. But what did I win ?`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`The service is still quite centralized.`}),`
`,(0,t.jsx)(n.li,{children:`I have really slow site accessbility.`}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`So I am really not sure if I will go down this road any further at this stage. I keep wondering how the master himself handles the storage of `,(0,t.jsx)(n.a,{href:`https://vitalik.eth.limo/`,children:`his blog`}),`. But I guess I will have to keep on reading and keep waiting for helpful insights.`]}),`
`,(0,t.jsxs)(n.section,{"data-footnotes":!0,className:`footnotes`,children:[(0,t.jsx)(n.h2,{className:`sr-only`,id:`footnote-label`,children:`Footnotes`}),`
`,(0,t.jsxs)(n.ol,{children:[`
`,(0,t.jsxs)(n.li,{id:`user-content-fn-2`,children:[`
`,(0,t.jsxs)(n.p,{children:[`The stuff done on `,(0,t.jsx)(n.a,{href:`https://app.uniswap.org/`,children:`Uniswap`}),` for example is quite impressive. `,(0,t.jsx)(n.a,{href:`#user-content-fnref-2`,"data-footnote-backref":``,"aria-label":`Back to reference 1`,className:`data-footnote-backref`,children:`↩`})]}),`
`]}),`
`,(0,t.jsxs)(n.li,{id:`user-content-fn-1`,children:[`
`,(0,t.jsxs)(n.p,{children:[`From my understanding Ethereum is THE biggest blockchain, which allows you to run smart contracts and quite energy efficient. It feels a bit like the Linux of the blockchain world. `,(0,t.jsx)(n.a,{href:`#user-content-fnref-1`,"data-footnote-backref":``,"aria-label":`Back to reference 2`,className:`data-footnote-backref`,children:`↩`})]}),`
`]}),`
`]}),`
`]})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};